test_that("dot_reduce computes right-associated matrix product", {
  A <- matrix(c(1, 2, 3, 4), 2, 2)
  B <- matrix(c(0, 1, 1, 0), 2, 2)
  C <- matrix(c(2, 0, 0, 2), 2, 2)

  expect_equal(dot_reduce(A, B, C), A %*% (B %*% C))
})

test_that("voxel_sizes and obliquity are consistent for cardinal axes", {
  aff <- diag(c(2, 3, 4, 1))
  expect_equal(voxel_sizes(aff), c(2, 3, 4))
  expect_equal(obliquity(aff), c(0, 0, 0))
})

test_that("ArrayLike3D respects drop when j supplied and k missing", {
  vol <- make_vol()
  res <- vol[,1, , drop=FALSE]
  expect_equal(dim(res), c(2,1,2))
})

test_that("ArrayLike4D numeric missing j path returns correct shape", {
  vec <- make_vec()
  res <- vec[1, , , , drop=FALSE]
  expect_equal(dim(res), c(1,2,2,2))
})

test_that("ArrayLike3D matrix indexing validates bounds", {
  vol <- make_vol()
  bad_idx <- matrix(c(3,1,1), ncol=3)
  expect_error(vol[bad_idx, drop=FALSE])
})

test_that("linear_access works for dense objects", {
  vol <- make_vol()
  expect_equal(linear_access(vol, 1:2), c(1,2))
  vec <- make_vec()
  expect_equal(linear_access(vec, 1:3), as.vector(array(1:16, dim=c(2,2,2,2)))[1:3])
})

test_that("sub_clusters errors on invalid IDs", {
  sp <- NeuroSpace(c(4L, 4L, 4L), c(1, 1, 1))
  mask <- LogicalNeuroVol(array(TRUE, c(4,4,4)), sp)
  cvol <- ClusteredNeuroVol(mask, rep(1:2, length.out = 64))

  expect_error(sub_clusters(cvol, 99L), "not found")
})
